#[AsActivityFormatter(log_name: 'bookings', supports_events: ['created', 'updated', 'cancelled'])]
final class BookingActivityFormatter implements ActivityFormatterInterface
{
    public function format(Activity $activity): FormattedActivity
    {
        // Render 'Alice booked Court 3 for tomorrow' with a facility-name chip
        return new FormattedActivity(
            description: $activity->description,
            chips: [
                ['label' => $activity->properties['facility_name'], 'kind' => 'facility', 'href' => "/facilities/{$activity->properties['facility_id']}"],
            ],
        );
    }
}

#[AsActivitySubscriber(log_name: 'bookings', events: ['cancelled'], queue: 'billing')]
final class OnBookingCancelledStartRefund
{
    public function handle(ActivityRecorded $event): void
    {
        // Programmatic reaction to a booking-cancellation activity
        RefundBookingJob::dispatch($event->activity->subject_id);
    }
}
